def assess(record: dict) -> str:
    required = {'metric', 'docs', 'case_id', 'query', 'version', 'expected_top'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = record.get("case_id") is not None
    return "PASS" if ok else 'REJECT_EMBEDDING_RANK'

